sql:
SELECT invoice_total
FROM invoices
WHERE created_at BETWEEN '2022-01-01' AND '2022-12-31';

SELECT I.invoice_id, I.invoice_total
FROM invoices AS I
JOIN disputes AS D ON I.invoice_id = D.invoice_id;

SELECT invoice_id, customer_id, invoice_total
FROM invoices
WHERE due_date = '2016-08-15' AND CAST(invoice_total AS REAL) > 100;

SELECT order_id, AVG(shipping_cost) AS average_shipping_cost
FROM shipping
GROUP BY order_id;

external_knowledge:
- 'typical refund price' refers to the average price of the products that have been associated with refunds;
- 'goods' refers to 'products';
- The refund context implies filtering invoices by the 'refunded' status.

sql:
SELECT COUNT(*)
FROM invoices
WHERE invoice_status_id = (
    SELECT status_id FROM invoice_status WHERE status_name = 'refunded'
);

SELECT o.customer_id, od.product_id, od.quantity, od.total_price
FROM orders o
JOIN order_details od ON o.order_id = od.order_id;

SELECT customer_id, COUNT(invoice_id) AS total_invoices
FROM invoices
GROUP BY customer_id;

SELECT resolution_status 
FROM disputes 
WHERE dispute_id = 0;

SELECT invoice_total, invoice_status_id, due_date
FROM invoices
WHERE invoice_status_id IN (SELECT status_id FROM invoice_status WHERE status_name IN ('pending', 'disputed'));
